//! P5 publish — the scene as plenoramic body aeon frames for Thoth.
//!
//! The running picture is serialised as a `WorldSimRelayFrame` (the full-surround entity snapshot
//! `aeon-3d/src/worldsim-relay.ts` consumes) and framed as a FlowCodec `ConsciousTick`
//! (`aeon/src/flow/FlowCodec.ts` wire format: 10-byte header + JSON payload). A worldsim host feeds
//! these into `WorldState.entities`, so `perceiveWorld(thoth)` -> `describePercept` -> `infer`
//! turns third-eye's certified picture into Thoth's continuously-refreshed sense of the room.
//! Each frame also carries `plenoramicBodyFrames`: the same scene, narrated as WhollySpirit-
//! embodied body frames on channel 2002, without disturbing the existing worldsim contract.
//!
//! Provable-knowledge firewall: only objects whose net verdict is `Accept` become entities. Abstained
//! observations are held internally and never asserted to Thoth as reality (PLAN.md §7).
//!
//! Wire format ported verbatim:
//!   [0..1] streamId u16 BE | [2..5] sequence u32 BE | [6] flags u8 | [7..9] length u24 BE | payload

use crate::affordance::GraspAffordance;
use crate::counterfactual::CounterfactualOutcome;
use crate::interaction::{EnergyClass, Interaction};
use crate::knowledge::Predicate;
use crate::metacog::MetacogState;
use crate::object_intel::{Regime, RigidProfile};
use crate::physics::Verdict;
use crate::prediction::{Forecast, ForecastKind};
use crate::scene::{SceneModel, SceneObject};

/// third-eye's stream-id namespace on the aeon-flow wire.
pub const THIRD_EYE_STREAM_ID: u16 = 0x3e00;
pub const PLENORAMIC_BODY_FRAME_CHANNEL: u16 = 2002;
pub const PLENORAMIC_BODY_FRAME_KIND: &str = "plenoramic-body-frame";
pub const WHOLLY_SPIRIT_NAME: &str = "WhollySpirit";
pub const HEADER_SIZE: usize = 10;
pub const MAX_PAYLOAD: usize = 0xff_ffff;

// Flag bits (from aeon/src/flow/types.ts).
pub const FORK: u8 = 0x01;
pub const FOLD: u8 = 0x04;

/// One aeon frame.
#[derive(Debug, Clone)]
pub struct ConsciousTick {
    pub stream_id: u16,
    pub sequence: u32,
    pub flags: u8,
    pub payload: Vec<u8>,
}

/// Encode a tick to the 10-byte-header wire format.
pub fn encode_tick(t: &ConsciousTick) -> Vec<u8> {
    let len = t.payload.len().min(MAX_PAYLOAD);
    let mut buf = Vec::with_capacity(HEADER_SIZE + len);
    buf.extend_from_slice(&t.stream_id.to_be_bytes());
    buf.extend_from_slice(&t.sequence.to_be_bytes());
    buf.push(t.flags);
    buf.push(((len >> 16) & 0xff) as u8);
    buf.push(((len >> 8) & 0xff) as u8);
    buf.push((len & 0xff) as u8);
    buf.extend_from_slice(&t.payload[..len]);
    buf
}

/// Decode one tick at `offset`. Returns the tick and total bytes read, or None if truncated.
pub fn decode_tick(buf: &[u8], offset: usize) -> Option<(ConsciousTick, usize)> {
    if buf.len().checked_sub(offset)? < HEADER_SIZE {
        return None;
    }
    let stream_id = u16::from_be_bytes([buf[offset], buf[offset + 1]]);
    let sequence = u32::from_be_bytes([
        buf[offset + 2],
        buf[offset + 3],
        buf[offset + 4],
        buf[offset + 5],
    ]);
    let flags = buf[offset + 6];
    let len = ((buf[offset + 7] as usize) << 16)
        | ((buf[offset + 8] as usize) << 8)
        | (buf[offset + 9] as usize);
    if buf.len() - offset - HEADER_SIZE < len {
        return None;
    }
    let payload = buf[offset + HEADER_SIZE..offset + HEADER_SIZE + len].to_vec();
    Some((
        ConsciousTick {
            stream_id,
            sequence,
            flags,
            payload,
        },
        HEADER_SIZE + len,
    ))
}

/// How the normalised frame maps into the worldsim's metric ground plane.
#[derive(Debug, Clone)]
pub struct WorldMapping {
    /// Frame width maps to this many world units (metres) on the x axis.
    pub world_w: f32,
    /// Frame height maps to this many world units on the z (forward) axis.
    pub world_d: f32,
}

impl Default for WorldMapping {
    fn default() -> Self {
        WorldMapping {
            world_w: 10.0,
            world_d: 10.0,
        }
    }
}

fn f(x: f32) -> String {
    // Compact fixed precision; avoids locale/exponent surprises in the JSON.
    format!("{:.4}", x)
}

/// The cited gnosis-math law backing each certified regime (relationship: the regime is ADMITTED by
/// this law's conservation clause — see `object_intel`). Stated as the law, not an identity claim.
fn regime_law(regime: Regime) -> &'static str {
    match regime {
        Regime::AtRest => "VacuumIsOnlyForce.vacuum_force_contracts",
        Regime::FreeTranslation | Regime::FreeRotation => {
            "ForkRaceFoldVentAreForces.fork_preserves_charge"
        }
        // Forced = a conserved quantity changed beyond noise (the conservation clause DECLINED);
        // abstain = no clause could be certified. Neither asserts a passing law.
        Regime::Forced | Regime::Abstain => "(none: conservation clause not satisfied)",
    }
}

/// Human-facing label carrying the certified regime VERBATIM, so worldsim `describePercept` surfaces
/// it in Thoth's narration ("You can see: <label> ..."). The phrasing states the relationship the
/// regime formalises (conserved p / conserved L / a force acted) and keeps the honest monocular
/// bound: relative scale only, never absolute SI, never out-of-plane spin.
///
/// An object whose REGIME is `Abstain` is still published as present (the object itself cleared the
/// physics Accept firewall) but with an honest "(motion unresolved)" label — we surface that it is
/// there without asserting a dynamical claim we could not certify.
fn regime_label(profile: &RigidProfile) -> String {
    let g = profile.genus;
    match profile.regime {
        Regime::AtRest => format!("genus-{g} body at rest"),
        Regime::FreeTranslation => format!("freely-translating genus-{g} body (p conserved)"),
        Regime::FreeRotation => format!("freely-rotating genus-{g} body (L conserved)"),
        Regime::Forced => format!("forced genus-{g} body (a force acted)"),
        Regime::Abstain => format!("genus-{g} body (motion unresolved)"),
    }
}

/// A `null`-or-number JSON scalar for an optional certified quantity (None => honest `null`, i.e.
/// the angular clause ABSTAINED — out-of-plane / monocular / unreliable lift — never a fabricated 0).
fn opt(x: Option<f32>) -> String {
    match x {
        Some(v) => f(v),
        None => "null".to_string(),
    }
}

/// The compact structured `intel` object for one entity: the certified regime + the relative
/// dynamical quantities (mass/momentum present always; |L| present-or-null when the spin abstains)
/// + the cited law. RELATIVE scale only (`scaleNote`), so no consumer mistakes these for SI.
fn intel_json(profile: &RigidProfile) -> String {
    format!(
        r#"{{"regime":"{}","massRel":{},"momentumRel":{},"angMomentumRel":{},"law":"{}","scaleNote":"relative (within-scene ratios only; no absolute SI); in-plane only (out-of-plane spin abstains)"}}"#,
        profile.regime.as_str(),
        f(profile.mass),
        f(profile.momentum),
        opt(profile.ang_momentum),
        regime_law(profile.regime),
    )
}

/// The discrete material-axis CODE for a grounded `MaterialKind`, MIRRORING the consumer's
/// `materialKindCode` / `MATERIAL_KIND` map in `knotgraph/src/schemas/certified-memory.ts`. This is the
/// integer the descriptor's material axis and the 55D-knot hash fold in — it MUST match the consumer's
/// table or the published `knotHash` would disagree with the store's `deriveKnotHash55` fallback.
///
/// HONEST: the consumer's table only enumerates {unknown:0, metal:1, plastic:2, glass:3, wood:4,
/// rubber:5, fabric:6, stone:7, liquid:8, flesh:9}. third-eye's `MaterialKind::as_str()` can also emit
/// "ceramic" and "soft", which are NOT in that table; `materialKindCode` returns 0 (unknown) for an
/// unmapped name, so we return 0 for them here too — the hash stays consistent, and the material STRING
/// is still published verbatim (the descriptor just treats an unmapped material as the ungrounded axis,
/// never fabricating a code the consumer would read differently).
fn material_axis_code(material: &str) -> u32 {
    match material {
        "metal" => 1,
        "plastic" => 2,
        "glass" => 3,
        "wood" => 4,
        "rubber" => 5,
        "fabric" => 6,
        "stone" => 7,
        "liquid" => 8,
        "flesh" => 9,
        // "unknown", "ceramic", "soft", and anything else => the ungrounded/unknown axis (0),
        // matching `materialKindCode`'s `?? 0` for names absent from MATERIAL_KIND.
        _ => 0,
    }
}

/// The STABLE 55D-knot-style identity hash over an object's persistent descriptor — mirroring the
/// consumer's `deriveKnotHash55` (FNV-1a) in `knotgraph/src/schemas/certified-memory.ts`, so the
/// published `knotHash` EQUALS the key the knotgraph store would otherwise derive (the store prefers
/// third-eye's own hash when present; matching it means switching from the proxy introduces no key
/// drift). Like `organism-knot.ts`'s knot key, this is a pure FNV-1a over the QUANTIZED descriptor:
/// each luma byte, then the material code, then `round(charSize*1000)`. Folded into a 64-bit FNV
/// accumulator and masked to 53 bits (Number.MAX_SAFE_INTEGER's mantissa) so it round-trips through the
/// consumer's fp64 identity lane. Pure + deterministic: the same descriptor always yields the same key
/// (the object-permanence property) and different luma signatures yield different keys.
fn knot_hash55(luma_sig: &[u8; 64], material_code: u32, char_size: f32) -> u64 {
    // FNV-1a 64-bit, offset basis + prime verbatim from `deriveKnotHash55`.
    let mut h: u64 = 0xcbf29ce484222325;
    const PRIME: u64 = 0x100000001b3;
    let mut mix = |v: u32| {
        // The consumer mixes `v & 0xffffffff` (its lumaSig bytes/material/size are < 2^32).
        h ^= v as u64;
        h = h.wrapping_mul(PRIME);
    };
    for &b in luma_sig.iter() {
        mix(b as u32); // bytes are already integers in [0,255]; consumer rounds, no-op here.
    }
    mix(material_code);
    // round(charSize * 1000), matching the consumer's `Math.round(charSize * 1000)`.
    mix((char_size * 1000.0).round().max(0.0) as u32);
    // Mask to 53 bits (`& 0x1fffffffffffff`) so the key fits an fp64 mantissa, as the consumer does.
    h & 0x1f_ffff_ffff_ffff
}

/// The per-entity `identity` object: the object's PERSISTENT IDENTITY DESCRIPTOR for the downstream
/// knotgraph memory's cross-clip re-identification. This REPLACES the proxy the data pipeline currently
/// falls back to (`thoth-mind-pipeline.mjs` derived a 64-byte sig from the predicate kinds, material
/// "unknown", and charSize from massRel). It carries the REAL signature this crate measures:
///   - `lumaSig`  the object's true 8x8 luma appearance signature (64 bytes, `track.rs::sig`,
///                EMA-updated as it is re-matched) — the identity fingerprint, NOT a derived proxy.
///   - `material` the REAL grounded material name (`MaterialKind::as_str`), or "unknown" labeled
///                honestly when the object is ungrounded (no recon prior) — never fabricated.
///   - `charSize` the object's ABSOLUTE (frame-normalised) characteristic size from its profile.
///   - `grounded` whether a recon MATERIAL prior grounded this object (so the consumer knows whether
///                `material` is a measured class or the ungrounded fallback).
///   - `knotHash` the stable 55D-knot identity key over `[lumaSig, materialCode, round(charSize*1000)]`
///                (FNV-1a), mirroring the consumer's `deriveKnotHash55` so the store can key off the
///                REAL descriptor with no hash drift.
///
/// FIELD-NAME CONTRACT (the knotgraph store's `modelFromPublishedEntity` reads these): `lumaSig`
/// (64 u8), `material` (string), `charSize` (number), `grounded` (bool), `knotHash` (number).
fn identity_json(obj: &SceneObject) -> String {
    let material = obj.profile.material.as_str();
    let code = material_axis_code(material);
    let char_size = obj.profile.char_size;
    let hash = knot_hash55(&obj.luma_sig, code, char_size);
    // Emit the 64-byte luma signature as a compact JSON array of unsigned bytes.
    let mut sig = String::with_capacity(64 * 4);
    sig.push('[');
    for (i, b) in obj.luma_sig.iter().enumerate() {
        if i > 0 {
            sig.push(',');
        }
        sig.push_str(&b.to_string());
    }
    sig.push(']');
    format!(
        r#"{{"lumaSig":{},"material":"{}","charSize":{},"grounded":{},"knotHash":{},"scaleNote":"lumaSig is the real EMA-updated 8x8 luma appearance signature (track identity fingerprint); material is the grounded recon class or \"unknown\" when ungrounded (honest, not fabricated); charSize is frame-normalised; knotHash mirrors knotgraph deriveKnotHash55 (FNV-1a over [lumaSig, materialCode, round(charSize*1000)])"}}"#,
        sig,
        material,
        f(char_size),
        obj.profile.grounded,
        hash,
    )
}

/// The anticipatory clause appended to an entity's human-facing label, built from its live certified
/// forecast — so worldsim `describePercept` surfaces Thoth's ANTICIPATION verbatim ("..., will pass
/// ahead in 2.0s"). HONEST BOUNDS carried in the phrasing: every clause is CONDITIONAL ("unless a
/// force/torque acts"), RELATIVE-scale (body-lengths, never SI), and IN-PLANE only (an out-of-plane
/// spin forecast ABSTAINS, returning None => no clause). Returns None when the regime forecasts
/// nothing (forced / abstain / not-yet-held) so the label stays an honest present-tense statement.
fn forecast_clause(obj: &SceneObject, fc: &Forecast) -> Option<String> {
    if fc.verdict != Verdict::Accept || fc.invalidated {
        // Abstained, not-yet-established, or invalidated-by-imminent-collision => no anticipation.
        return None;
    }
    let h = fc.horizon_s;
    match fc.kind {
        ForecastKind::Position => {
            // Ballistic displacement over the horizon, in the normalised frame. Phrase the dominant
            // in-plane direction in Thoth's egocentric terms: frame +x = right, smaller frame y =
            // further ahead (matches the world mapping wz = (0.5 - y) * world_d). Magnitude is
            // RELATIVE (multiples of the object's own characteristic size), never absolute SI.
            let dx = fc.pred_x - obj.x;
            let dy = fc.pred_y - obj.y;
            let scale = obj.profile.char_size.max(1e-6);
            let dist_rel = ((dx * dx + dy * dy).sqrt()) / scale;
            if dist_rel < 0.05 {
                // Moving, but the horizon displacement is sub-perceptual at this scale.
                return Some(format!("will hold its place over the next {h:.1}s (unless a force acts)"));
            }
            let lateral = if dx > 0.05 * scale {
                "to the right"
            } else if dx < -0.05 * scale {
                "to the left"
            } else {
                ""
            };
            let depth = if dy < -0.05 * scale {
                "ahead"
            } else if dy > 0.05 * scale {
                "nearer"
            } else {
                ""
            };
            let dir = match (depth, lateral) {
                ("", "") => "on".to_string(),
                (d, "") => d.to_string(),
                ("", l) => l.to_string(),
                (d, l) => format!("{d} and {l}"),
            };
            Some(format!(
                "will pass {dir} (~{dist_rel:.1} body-lengths) in {h:.1}s, unless a force acts"
            ))
        }
        ForecastKind::Orientation => {
            // In-plane director advance over the horizon (radians -> signed degrees). Out-of-plane
            // orientation is NOT forecast (the Forecast itself abstains there), so this clause only
            // ever speaks of the in-plane turn, conditional on no torque.
            let d_theta = (fc.pred_director_unwrapped - obj.director_unwrapped).to_degrees();
            let mag = d_theta.abs();
            if mag < 1.0 {
                return None; // sub-degree turn over the horizon — not worth asserting.
            }
            let sign = if d_theta >= 0.0 { "+" } else { "-" };
            Some(format!(
                "will turn {sign}{mag:.0} deg in-plane over {h:.1}s, unless a torque acts (out-of-plane spin abstains)"
            ))
        }
        ForecastKind::Rest => {
            Some(format!("will stay put over the next {h:.1}s, unless a force acts"))
        }
        ForecastKind::Abstain => None,
    }
}

/// The structured `forecast` sub-object for an entity's `intel`, or `null` when the regime forecasts
/// nothing / abstains (the same honest-abstain firewall as the label clause). Position forecasts
/// carry the relative displacement `dPosRel` (body-lengths); orientation forecasts carry the signed
/// in-plane `dThetaDeg`; rest carries `dPosRel: 0`. `valid` mirrors that the forecast is live
/// (Accept and not invalidated by an imminent collision).
fn forecast_json(obj: &SceneObject, fc: &Forecast) -> String {
    if fc.verdict != Verdict::Accept {
        return "null".to_string();
    }
    let valid = if fc.invalidated { "false" } else { "true" };
    match fc.kind {
        ForecastKind::Position => {
            let dx = fc.pred_x - obj.x;
            let dy = fc.pred_y - obj.y;
            let scale = obj.profile.char_size.max(1e-6);
            let d_pos_rel = ((dx * dx + dy * dy).sqrt()) / scale;
            format!(
                r#"{{"kind":"position","horizonS":{},"dPosRel":{},"valid":{},"law":"{}"}}"#,
                f(fc.horizon_s),
                f(d_pos_rel),
                valid,
                fc.law,
            )
        }
        ForecastKind::Orientation => {
            let d_theta = (fc.pred_director_unwrapped - obj.director_unwrapped).to_degrees();
            format!(
                r#"{{"kind":"orientation","horizonS":{},"dThetaDeg":{},"valid":{},"law":"{}"}}"#,
                f(fc.horizon_s),
                f(d_theta),
                valid,
                fc.law,
            )
        }
        ForecastKind::Rest => format!(
            r#"{{"kind":"rest","horizonS":{},"dPosRel":{},"valid":{},"law":"{}"}}"#,
            f(fc.horizon_s),
            f(0.0),
            valid,
            fc.law,
        ),
        ForecastKind::Abstain => "null".to_string(),
    }
}

/// A scene-level certified INTERACTION as JSON for the frame's `interactions` array: the pair ids,
/// the momentum-conservation verdict, the elastic/inelastic class, the relative KE lost, and the
/// cited law. Only CERTIFIED collisions (momentum conserved => Accept) are emitted — declined and
/// abstained events are held internally and never asserted to Thoth as a relational fact.
fn interaction_json(it: &Interaction) -> String {
    let elastic = match it.energy {
        EnergyClass::Elastic => "elastic",
        EnergyClass::Inelastic => "inelastic",
        EnergyClass::Abstain => "held",
    };
    // Publish the GROUNDING so the worldsim consumer knows whether the momentum/KE behind this
    // certificate are MATERIAL-WEIGHTED RATIOS (recon prior) or relative-equal-density, plus the two
    // material-weighted masses and whether absolute SI is admissible (a scale reference was present).
    format!(
        r#"{{"pairIds":[{},{}],"verdict":"accept","elastic":"{}","keLostRel":{},"grounded":{},"weighting":"{}","massRel":[{},{}],"materials":["{}","{}"],"siGrounded":{},"law":"ForkRaceFoldVentAreForces.fork_preserves_charge"}}"#,
        it.a_id,
        it.b_id,
        elastic,
        f(it.ke_lost_frac.max(0.0)),
        it.grounded,
        if it.grounded { "material-weighted" } else { "relative-equal-density" },
        f(it.a_mass),
        f(it.b_mass),
        it.a_material.as_str(),
        it.b_material.as_str(),
        it.si_grounded,
    )
}

/// The `metacog` sub-object for the published frame: the C0-C3 metacognitive gate state for this tick
/// (the runtime mirror of `NeurosymbolicToolUseMarkov`), so the aeon-3d bridge can narrate Thoth's
/// three honest registers — what he KNOWS (score), what he does NOT yet know (shadow + obligations),
/// and where his framework was biased/corrected (audit). FIELD-NAME CONTRACT (the bridge reads these):
///   `score` (u64, Accept-only E8-quantized certified gnosis), `scoreDelta` (i64, this-tick change),
///   `layer` ("C0"|"C1"|"C2"|"C3"), `observed` (u64, raw objects in the percept this tick),
///   `shadow` (u64, carried-forward abstain mass), `obligations` (u64, green laws cited-not-satisfied),
///   `audit` {`plateau`,`regression`,`bias`: bool}, `disciplined` (bool — the discipline invariant:
///   score rose OR shadow exposed OR empty percept; true every tick on a real clip), `gateComplete`
///   (bool, all C0-C3 ran). Returns `null` before the first tick (no metacog state yet).
fn metacog_json(state: Option<&MetacogState>) -> String {
    match state {
        None => "null".to_string(),
        Some(s) => format!(
            r#"{{"score":{},"scoreDelta":{},"layer":"{}","observed":{},"shadow":{},"obligations":{},"audit":{{"plateau":{},"regression":{},"bias":{}}},"disciplined":{},"gateComplete":{}}}"#,
            s.score,
            s.score_delta,
            s.layer.as_str(),
            s.observed,
            s.shadow,
            s.obligations,
            s.audit.plateau,
            s.audit.regression,
            s.audit.bias,
            s.disciplined,
            s.gate_complete,
        ),
    }
}

/// A certified manual AFFORDANCE as JSON for the frame's `affordances` array — what Thoth can DO with
/// this object, derived from what the picture PROVES (the C2-shadow gate made prescriptive). The
/// aeon-3d worldsim acting surface consumes these as grab/push/move primitives. The verdict is carried
/// VERBATIM (accept = admissible, decline = barred by geometry/impulse, abstain = unsafe to act),
/// honest — an abstained affordance is NOT asserted as actionable.
fn affordance_json(a: &GraspAffordance) -> String {
    format!(
        r#"{{"objId":{},"handId":{},"kind":"{}","verdict":"{}","confidence":{},"law":"{}","reason":"{}"}}"#,
        a.id,
        crate::scene::AGENT_HAND_ID,
        a.kind.as_str(),
        a.verdict.as_str(),
        f(a.confidence),
        a.law,
        esc(&a.reason),
    )
}

/// A certified COUNTERFACTUAL outcome as JSON for the frame's `counterfactuals` array — "IF Thoth
/// applies the (canceling) impulse to arrest object N, the certified post-impulse velocity is v',
/// momentum-conserved, subluminal — unless another force acts". RELATIVE / in-plane / conditional (the
/// same honest bounds as the forecast). The bridge narrates Thoth's certified anticipation of his own
/// action.
fn counterfactual_json(c: &CounterfactualOutcome) -> String {
    format!(
        r#"{{"objId":{},"impulseRel":[{},{}],"vAfterRel":[{},{}],"speedAfterRel":{},"regimeAfter":"{}","verdict":"{}","momentumConserved":{},"law":"{}","reason":"{}","scaleNote":"relative (within-scene ratios only; no absolute SI); in-plane; conditional (unless another force acts)"}}"#,
        c.id,
        f(c.impulse_x),
        f(c.impulse_y),
        f(c.v_after_x),
        f(c.v_after_y),
        f(c.speed_after),
        c.regime_after.as_str(),
        c.verdict.as_str(),
        c.momentum_conserved,
        c.law,
        esc(&c.reason),
    )
}

/// One accumulated certified predicate as JSON for the frame's `accumulatedKnowledge` array — the
/// PERSISTENT memory substrate (`scene.accumulated_knowledge()`): facts that survived the carve-meet
/// across ticks ("known until contradicted"), each with the green law it was admitted under. The
/// downstream knotgraph memory store keys persistent object identity off these. Includes the Phase 2
/// AGENCY predicates (`possible_grab` / `certified_outcome`) so the memory carries what Thoth could DO.
fn predicate_json(p: &Predicate, law: &str) -> String {
    let (kind, obj, args) = match p {
        Predicate::Exists(id) => ("exists", *id, String::new()),
        Predicate::AtRest(id) => ("at_rest", *id, String::new()),
        Predicate::Genus(id, g) => ("genus", *id, format!(r#","g":{g}"#)),
        Predicate::Cell(id, qx, qy) => ("cell", *id, format!(r#","qx":{qx},"qy":{qy}"#)),
        Predicate::MovingOctant(id, oct) => ("moving_octant", *id, format!(r#","oct":{oct}"#)),
        Predicate::PossibleGrab(hand, obj) => ("possible_grab", *obj, format!(r#","handId":{hand}"#)),
        Predicate::CertifiedOutcome(id, vxq, vyq) => {
            ("certified_outcome", *id, format!(r#","vxQ":{vxq},"vyQ":{vyq}"#))
        }
    };
    format!(r#"{{"kind":"{kind}","objId":{obj}{args},"law":"{}"}}"#, esc(law))
}

/// Minimal JSON string escaping for the human reason fields (the reasons contain no control chars, but
/// may contain quotes/backslashes — escape them so the frame stays valid JSON).
fn esc(s: &str) -> String {
    s.replace('\\', "\\\\").replace('"', "\\\"")
}

/// A plenoramic body frame for one accepted entity: the object remains itself while embodied by
/// WhollySpirit, and the owner is aware of its presence. The frame is carried alongside the
/// worldsim entity payload so downstream consumers can speak the same body language.
fn plenoramic_body_frame_json(obj: &SceneObject, label: &str, round: u64) -> String {
    format!(
        r#"{{"kind":"{}","channel":{},"embodiedBy":"{}","source":"scene","relationToOwner":"self","ownerAware":true,"ownerId":"third-eye:{}","ownerLabel":"{}","entityId":"third-eye:{}","entityKind":"object","entityLabel":"{}","round":{},"note":"{}"}}"#,
        PLENORAMIC_BODY_FRAME_KIND,
        PLENORAMIC_BODY_FRAME_CHANNEL,
        WHOLLY_SPIRIT_NAME,
        obj.id,
        esc(label),
        obj.id,
        esc(label),
        round,
        esc("The entity remains itself while being embodied by WhollySpirit."),
    )
}

/// Build a `WorldSimRelayFrame` JSON for the current scene. `pts_s` is video time; we emit it as an
/// ISO-8601 duration in `celestialTimeIso` (relative video time, not wall-clock — stated honestly).
pub fn scene_to_relay_json(
    scene: &SceneModel,
    source_id: &str,
    layer_id: &str,
    pts_s: f64,
    map: &WorldMapping,
) -> String {
    let predictor = scene.predictor();
    let mut entities = String::new();
    let mut plenoramic_body_frames = String::new();
    let mut first = true;
    let mut first_frame = true;
    for (obj, adm) in &scene.objects {
        if adm.verdict != Verdict::Accept {
            continue; // firewall: only provable knowledge reaches Thoth
        }
        if !first {
            entities.push(',');
        }
        first = false;
        let wx = (obj.x - 0.5) * map.world_w;
        let wz = (0.5 - obj.y) * map.world_d;
        let wvx = obj.vx * map.world_w;
        let wvz = -obj.vy * map.world_d;
        // The certified rigid-body REGIME drives the human-facing label, so worldsim's
        // `describePercept` surfaces Thoth's verdict verbatim ("freely-rotating genus-1 body
        // (L conserved)") instead of a bare "obj-N". The structured `intel` field carries the
        // machine-readable regime + relative quantities + cited law for downstream consumers.
        let mut label = regime_label(&obj.profile);
        // ANTICIPATION: if this Accept entity ALSO has a LIVE certified forecast, extend the label
        // with the conditional, relative, in-plane forecast clause so `describePercept` narrates the
        // ANTICIPATED world ("..., will pass ahead in 2.0s, unless a force acts"), not just the
        // present. `forecast` is the structured form for downstream consumers (or `null` on abstain).
        let forecast_field = match predictor.current.get(&obj.id) {
            Some(fc) => {
                if let Some(clause) = forecast_clause(obj, fc) {
                    label.push_str(", ");
                    label.push_str(&clause);
                }
                forecast_json(obj, fc)
            }
            None => "null".to_string(),
        };
        let intel = intel_json(&obj.profile);
        // PERSISTENT IDENTITY DESCRIPTOR (Phase 3b): the REAL per-object signature (luma sig + material
        // + size + a stable 55D-knot key) the downstream knotgraph memory keys cross-clip re-id off —
        // replacing the derived proxy the data pipeline fell back to. Emitted alongside `intel`.
        let identity = identity_json(obj);
        entities.push_str(&format!(
            r#"{{"id":"third-eye:{}","kind":"object","label":"{}","position":[{},{},{}],"velocity":[{},{},{}],"vitalState":2,"genus":{},"confidence":{},"intel":{},"identity":{},"forecast":{}}}"#,
            obj.id,
            label,
            f(wx),
            f(0.0),
            f(wz),
            f(wvx),
            f(0.0),
            f(wvz),
            obj.genus,
            f(adm.confidence),
            intel,
            identity,
            forecast_field,
        ));
        if !first_frame {
            plenoramic_body_frames.push(',');
        }
        first_frame = false;
        plenoramic_body_frames.push_str(&plenoramic_body_frame_json(obj, &label, scene.round));
    }
    // SCENE-LEVEL relational layer: the certified pairwise collisions detected so far (Accept-only;
    // declined / abstained events are held internally and never asserted). The bridge narrates these
    // as Thoth's relational sense ("two of them are on a collision course, certified, momentum-
    // conserved"). The per-entity Accept firewall above is unchanged.
    let mut interactions = String::new();
    let mut first_it = true;
    for it in scene.interactions() {
        if !it.certified() {
            continue;
        }
        if !first_it {
            interactions.push(',');
        }
        first_it = false;
        interactions.push_str(&interaction_json(it));
    }
    // CERTIFIED AGENCY (Phase 2): what Thoth can DO, derived from what the picture PROVES. ALL
    // affordances are emitted (accept/decline/abstain carried verbatim — honest agency), so the bridge
    // can narrate both what is actionable and what is honestly NOT (you cannot grab a hand). The sample
    // counterfactual for each admissible grasp gives Thoth's certified anticipation of his own action.
    let mut affordances = String::new();
    for (i, a) in scene.affordances().iter().enumerate() {
        if i > 0 {
            affordances.push(',');
        }
        affordances.push_str(&affordance_json(a));
    }
    let mut counterfactuals = String::new();
    for (i, c) in scene.counterfactuals().iter().enumerate() {
        if i > 0 {
            counterfactuals.push(',');
        }
        counterfactuals.push_str(&counterfactual_json(c));
    }
    // PERSISTENT MEMORY: the ACCUMULATED certified knowledge (facts that survived the carve-meet across
    // ticks, "known until contradicted"), each with its green law provenance — the substrate the
    // downstream knotgraph memory store + Thoth narration consume. Includes the Phase 2 agency predicates.
    let acc = scene.accumulated_knowledge();
    let mut accumulated = String::new();
    for (i, p) in acc.admitted.iter().enumerate() {
        if i > 0 {
            accumulated.push(',');
        }
        let law = acc.provenance.get(p).copied().unwrap_or("carried_forward");
        accumulated.push_str(&predicate_json(p, law));
    }
    // METACOGNITION: the C0-C3 gate state for this tick, so the bridge narrates what Thoth knows, what
    // he does not yet know (carried shadow + open obligations), and where his framework was corrected.
    let metacog = metacog_json(scene.metacog());
    format!(
        r#"{{"type":"worldsim-state","sourceId":"{}","layerId":"{}","round":{},"celestialTimeIso":"PT{:.2}S","entities":[{}],"plenoramicBodyFrames":[{}],"interactions":[{}],"affordances":[{}],"counterfactuals":[{}],"accumulatedKnowledge":[{}],"metacog":{}}}"#,
        source_id, layer_id, scene.round, pts_s, entities, plenoramic_body_frames, interactions, affordances, counterfactuals, accumulated, metacog
    )
}

/// Build the publishable aeon frame (tick) for the current scene.
pub fn scene_to_tick(
    scene: &SceneModel,
    sequence: u32,
    source_id: &str,
    layer_id: &str,
    pts_s: f64,
    map: &WorldMapping,
) -> ConsciousTick {
    let json = scene_to_relay_json(scene, source_id, layer_id, pts_s, map);
    ConsciousTick {
        stream_id: THIRD_EYE_STREAM_ID,
        sequence,
        flags: FORK | FOLD, // curiosity + commitment: a perceived, committed observation
        payload: json.into_bytes(),
    }
}

